it('should deliver notifications in order even with slow adapters', async () => {
  const deliveryOrder: string[] = [];

  const slowEmailAdapter: NotificationAdapter = {
    channel: 'email',
    send: (payload: NotificationPayload): Promise<NotificationResult> => {
      // First notification (order confirmation) takes longer to deliver
      const delay = payload.type === 'order-confirmation' ? 50 : 10;
      return new Promise((resolve) => {
        setTimeout(() => {
          deliveryOrder.push(payload.type);
          resolve({ success: true, channel: 'email' });
        }, delay);
      });
    },
  };

  const orderedService = new NotificationService(eventBus, [slowEmailAdapter]);

  const orderCreatedEvent: OrderCreatedEvent = {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [
        { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
      ],
      total: 10,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
  };

  const statusChangedEvent: OrderStatusChangedEvent = {
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [],
      total: 10,
      status: 'confirmed',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    previousStatus: 'pending',
    newStatus: 'confirmed',
    timestamp: new Date(),
  };

  // Fire both events — order:created first, then status change
  await eventBus.emit(orderCreatedEvent);
  statusChangeCallbacks.notify(statusChangedEvent);

  // Wait for the queue to drain
  await new Promise((resolve) => setTimeout(resolve, 150));

